mapper.select:
SELECT a.ID "trustCargoId", A.TRUST_ID "trustId", b.CARGO_INFO_NO "cargoInfoNo", D.SHIP_NAME "shipName", D.VOYAGE "voyage", D.START_TIME, D.END_TIME, b.CARGO_OWNER_NAME "cargoOwnerName", b.CARGO_OWNER_ID, D .TRUST_NO "trustNo", D.PORT_CODE "workAreaCd", D.PORT_NAME "workAreaNm", b.PACKING_NAME "packingName", A.INNERTRANSPORT_TYPE, A.STATUS, A.TRANSPORT_TYPE, A.IS_RULE, A.EMPTY_WEIGHT, A.HEAVY_WEIGHT, MC.CARGO_CODE, A.BUSINESS_NO, A.PRINT_POUND_ID, A.PRINT_POUND_NUM, TBT.TRUST_TYPE, CASE WHEN MC.SIGN IS NOT NULL THEN MC.CARGO_NAME || '(' || MC.SIGN || ')' ELSE MC.CARGO_NAME END CARGO_NAME FROM T_BUS_TRUST_CARGO A LEFT JOIN T_BUS_CARGO_INFO b ON b. ID = A .CARGO_INFO_ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM c ON b.SHIPVOYAGE_ITEM_ID = c. ID LEFT JOIN T_BUS_TRUST D ON A .TRUST_ID = D . ID LEFT JOIN M_CARGO MC ON A.CARGO_CODE = MC.CARGO_CODE LEFT JOIN T_BUS_TRUST TBT ON TBT.ID = A.TRUST_ID
A.IS_SECOND_WEIGH = '1'
AND b.CARGO_INFO_NO LIKE #{cargoInfoNo_like}
AND b.CARGO_OWNER_ID LIKE #{cargoOwnerId_like}
AND A.STATUS = #{status,jdbcType=VARCHAR}
AND MC.CARGO_CODE = #{cargoCode,jdbcType=VARCHAR}
AND A.BUSINESS_NO = #{businessNo,jdbcType=VARCHAR}
AND D.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId, jdbcType=BIGINT}

mapper.update:
UPDATE
	T_BUS_TRUST_CARGO
SET INNERTRANSPORT_TYPE = #{innertransportType,jdbcType=VARCHAR}
WHERE ID = #{id,jdbcType=BIGINT}

update
T_BUS_VEHICLE_TRANSFER
set
status = #{status}
where
id = #{id}

update
T_BUS_VEHICLE_TRANSFER
set
DEL_FLAG = #{delFlag, jdbcType=BIGINT}
where
id = #{id}

mapper.select:
SELECT count(*)
FROM WFG_PORTMIS_POUND.WEIGHT_RECORD_POUND
where PLAN_NO != #{businessNo}  AND IS_FINISHED = '0' AND TRUCK_PLATE = #{equipmentNo}

SELECT COUNT(*)
from WFG_PORTMIS_POUND.WEIGHT_RECORD_POUND PP
WHERE IS_DELETE = '0'
  AND TSPT_ID IN (
select TO_CHAR(ID) FROM  T_BUS_VEHICLE_TRANSFER
WHERE TRUST_CARGO_ID = #{trustCargoId,jdbcType=BIGINT}
  AND TRUST_ID = #{trustId,jdbcType=BIGINT}
  AND EQUIPMENT_ID = #{equipmentId,jdbcType=VARCHAR}
)
